package genxsolution.vms.vmsbackend.vehicle_management.vehicle.controller;
import genxsolution.vms.vmsbackend.common.query.ListQueryEngine; import genxsolution.vms.vmsbackend.vehicle_management.vehicle.dto.*; import genxsolution.vms.vmsbackend.vehicle_management.vehicle.service.VehicleService; import org.springframework.http.HttpStatus; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api/v1/vehicles/records") public class VehicleController { private final VehicleService service; public VehicleController(VehicleService service){this.service=service;} @GetMapping public List<VehicleResponse> list(@RequestParam(required=false) UUID companyId,@RequestParam Map<String,String> filters){ return ListQueryEngine.apply(service.list(companyId), filters, Set.of("companyId")); } @GetMapping("/{id}") public VehicleResponse getById(@PathVariable UUID id){ return service.getById(id);} @PostMapping @ResponseStatus(HttpStatus.CREATED) public VehicleResponse create(@RequestBody VehicleUpsertRequest r){ return service.create(r);} @PutMapping("/{id}") public VehicleResponse update(@PathVariable UUID id,@RequestBody VehicleUpsertRequest r){ return service.update(id,r);} @DeleteMapping("/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) public void delete(@PathVariable UUID id){ service.delete(id);} }
